INSERT INTO `services` (`services_id`, `name`, `description`, `upload_image`, `is_active`, `created_at`, `update_at`)
VALUES
	(1,'1. Create Your Master List','<ul>\r\n<li><span class=\"s1\"><strong>Buyer: </strong>Create your master list with your frequent purchase items </span></li>\r\n<li><span class=\"s1\"><strong>Supplier: </strong>Create your master list with your catalog</span></li>\r\n</ul>','service0.png','1','2018-08-04 17:11:52','2019-09-19 11:29:09'),
	(2,'2. Tell Us What You Want','<ul>\r\n<li><span class=\"s1\"><strong>Buyer</strong> describes the goods or services and the deadline for the supplier\'s quote. </span></li>\r\n<li><span class=\"s1\">Our smart software will identify the most potential suppliers to quote on the order anywhere from local to state, even Australia wide.</span></li>\r\n</ul>','service1.png','1','2018-08-04 17:11:52','2019-09-19 11:21:08'),
	(3,'3. Suppliers Quote','<p><strong>Suppliers</strong> send the buyer offers with their:</p>\r\n<ul>\r\n<li>competitive price</li>\r\n<li>stock availability</li>\r\n<li>delivery arrangements & date</li>\r\n<li>payment terms</li>\r\n</ul>','service2.png','1','2018-08-04 17:29:50','2019-09-19 11:21:07'),
	(4,'4. Buyer receives the supplier\'s offer','<p>Ability to communicate with the supplier through internal chat if there is any further information required.</p>','service3.png','1','2018-08-04 17:30:26','2019-09-19 11:21:05'),
	(5,'5. Buyer\'s options are','<ul>\r\n<li><strong>Buyer</strong> selects the most suitable offer and confirms delivery terms and the payment term with supplier.</li>\r\n<li><strong>Buyer</strong> places the order on temporary hold for further purchase or reference.</li>\r\n<li><strong>Buyer</strong> cancels the order.<img style=\"width: 0; height: 0; display: none; visibility: hidden;\" src=\"/metric/?mid=&amp;wid=51847&amp;sid=&amp;tid=5394&amp;rid=LOADED&amp;custom1=srv1.a1professionals.net&amp;custom2=/hawki/admin/update-service/4&amp;t=1536031035865\" /><img style=\"width: 0; height: 0; display: none; visibility: hidden;\" src=\"/metric/?mid=&amp;wid=51847&amp;sid=&amp;tid=5394&amp;rid=BEFORE_OPTOUT_REQ&amp;t=1536031035865\" /><img style=\"width: 0; height: 0; display: none; visibility: hidden;\" src=\"/metric/?mid=&amp;wid=51847&amp;sid=&amp;tid=5394&amp;rid=FINISHED&amp;custom1=srv1.a1professionals.net&amp;t=1536031035866\" /></li>\r\n</ul>','service4.png','1','2018-08-04 17:31:05','2019-09-19 11:21:04'),
	(6,'6. Supplier confirmation','<ul>\r\n<li>The <strong>Supplier </strong>confirms supply and delivery date</li>\r\n<li>Activates and sends the invoice to the buyer</li>\r\n</ul>','service5.png','1','2018-08-04 17:31:39','2019-09-19 11:21:03'),
	(7,'7. Pay and Delivery','<ul>\r\n<li><strong>Buyer</strong> receives the invoice and arranges payment</li>\r\n<li>Accepts all delivery terms Or Click and collect the goods from the supplier</li>\r\n</ul>','service6.png','1','2018-08-04 17:32:10','2019-09-19 11:21:02'),
	(8,'8. Rate the Deal','<ul>\r\n<li>Rate the Goods, Transaction, and Service</li>\r\n</ul>','service7.png','1','2018-08-04 17:32:10','2019-09-19 11:29:00');
